+// ---------------------------------------------------------------------------
+
+#[test]
+fn test_workload_domain_count_is_twelve() {
+    assert_eq!(WorkloadDomain::count(), 12);
+    assert_eq!(WorkloadDomain::ALL.len(), 12);
+}
