+fn test_workload_domain_display_all_twelve() {
+    let expected = [
+        "branch_heavy",
+        "vectorizable",
+        "proof_specialized",
+        "native_addon",
+        "hostcall_boundary",
+        "startup_image",
+        "metadata_locality",
+        "observability_sensitive",
+        "resource_bounded",
+        "string_regexp",
+        "react_lifecycle",
+        "async_iterator",
+    ];
+    for (domain, name) in WorkloadDomain::ALL.iter().zip(expected.iter()) {
+        assert_eq!(domain.to_string(), *name);
+        assert_eq!(domain.as_str(), *name);
+    }
+}
