+#[test]
+fn test_counterexample_hash_deterministic() {
+    let seed_hash = ContentHash::compute(b"seed");
+    let a = Counterexample::new(
+        100_000,
+        WorkloadDomain::BranchHeavy,
+        FalsificationStrategy::RandomMutation,
+        seed_hash,
+        1_000_000,
+    );
+    let b = Counterexample::new(
+        100_000,
+        WorkloadDomain::BranchHeavy,
