+    // Line 2 has std_fs exempted, line 3 does not
+    let exempted_count = findings
+        .iter()
+        .filter(|f| f.exempted && f.pattern_id == "std_fs")
+        .count();
+    let violated_count = findings
+        .iter()
+        .filter(|f| !f.exempted && f.pattern_id == "std_fs")
+        .count();
+    assert_eq!(exempted_count, 1);
+    assert!(violated_count >= 1);
+}
