+    let program = Program {
+        constants: vec![Value::Int(100)],
+        property_pool: Vec::new(),
+        instructions: vec![
+            Instruction::JumpIfFalse {
+                condition: r(0),
+                target: 2,
+            },
+            Instruction::LoadConst {
+                dst: r(1),
+                const_index: 0,
+            },
+            Instruction::Return { src: r(0) },
+        ],
