+    let mut vm = BytecodeVm::new("t", 4, 32);
+    let report = vm.execute(&program).unwrap();
+    assert_eq!(report.result, Value::Undefined);
+    assert_eq!(report.steps, 2); // JumpIfFalse + Return, skipped LoadConst
+}
