+fn make_proximity(
+    distance: i64,
+    kind: BoundaryKind,
+    region: PhaseRegion,
+    probes: u32,
+    confidence: i64,
+) -> CliffProximity {
+    CliffProximity {
+        distance_millionths: distance,
+        boundary_kind: kind,
+        current_region: region,
+        probe_count: probes,
+        confidence_millionths: confidence,
+    }
