+fn make_claim(name: &str, claimed: i64, threshold: i64, higher_is_better: bool) -> MetricClaim {
+    MetricClaim {
+        metric_name: name.to_string(),
+        claimed_value_millionths: claimed,
+        threshold_millionths: threshold,
+        higher_is_better,
+    }
+}
